mapper.select:
SELECT  SC.MASTER_ID::TEXT AS STORY_ID , SM.TITLE , SC.SUMMARY , SC.IS_VERIFIED , SC.TAGS   
FROM STORY_CONTENT SC
   JOIN STORY_MASTER SM ON SC.MASTER_ID = SM.ID 
WHERE 1=1
AND   SC.CHAR_CODE = #{charCode}
AND   SC.PLA_CODE  = #{plaCode}
AND   SC.MOD_CODE  = #{modCode}
AND   SC.EVE_CODE  = #{eveCode}
AND   SC.COM_CODE  = #{comCode}
AND   SC.PRO_CODE  = #{proCode}
AND   SC.ACT_CODE  = #{actCode}
AND   SC.SOL_CODE  = #{solCode}
AND   SC.END_CODE  = #{endCode}
AND   SC.IS_VERIFIED = TRUE
ORDER BY SC.CREATED_AT DESC
LIMIT 1
